{"procName":"dbo.tr_order_example_detail_update2","body":"CREATE PROC [dbo].[TR_ORDER_EXAMPLE_DETAIL_UPDATE2]
(
	@id int,
	@customer nvarchar(100),
	@agent nvarchar(100),
	@range nvarchar(100),
	@order_number nvarchar(100),
	@item_number nvarchar(100),
	@cust_item_number nvarchar(MAX),
	@description nvarchar(MAX),
	@color nvarchar(MAX),
	@material nvarchar(MAX),
	@order_qty int,
	@cbm decimal(18, 5),
	@price decimal(18, 3),
	@currency nvarchar(50),
	@amount decimal(18, 3),
	@bill_to nvarchar(MAX),
	@ship_to nvarchar(MAX),
	@input_qty int,
	@destination_port nvarchar(50),
	@etd date,
	@ship_date date,
	@ship_qty int,
	@order_date date,
	@cont_date date,
	@container_size nvarchar(MAX),
	@nccht nvarchar(MAX),
	@payment_term nvarchar(MAX),
	@remark nvarchar(MAX),
	@cust_po_number nvarchar(MAX),
	@attribute4 nvarchar(50),
	@choduyet nvarchar(50),
	@f_cancelled nvarchar(2),
	@Finished bit,
	@IsRelease bit,
	@create_by nvarchar(50),
	@create_date datetime,
	@update_by nvarchar(50),
	@update_date datetime,
	@test_run_qty int = 0,
	@mact nvarchar(50),
	@nguyenbo bit
)
AS
DECLARE @tenct nvarchar(100) = ''
DECLARE @nguyenlieu nvarchar(100) = ''
DECLARE @quycach nvarchar(100) = ''

SELECT @tenct = tenvt, @nguyenlieu = nguyenlieu, @quycach = quycach 
FROM tr_material 
WHERE mavt = @mact

UPDATE tr_order_example_detail
SET
	customer = @customer,
	agent = @agent,
	[range] = @range,
	order_number = @order_number,
	item_number = @item_number,
	cust_item_number = @cust_item_number,
	[description] = @description,
	color = @color,
	material = @material,
	order_qty = @order_qty,
	cbm = @cbm,
	price = @price,
	currency = @currency,
	amount = @amount,
	bill_to = @bill_to,
	ship_to = @ship_to,
	input_qty = @input_qty,
	destination_port = @destination_port,
	etd = @etd,
	ship_date = @ship_date,
	ship_qty = @ship_qty,
	order_date = @order_date,
	cont_date = @cont_date,
	container_size = @container_size,
	nccht = @nccht,
	payment_term = @payment_term,
	remark = @remark,
	cust_po_number = @cust_po_number,
	attribute4 = @attribute4,
	choduyet = @choduyet,
	f_cancelled = @f_cancelled,
	Finished = @Finished,
	IsRelease = @IsRelease,
	update_by = @update_by,
	update_date = @update_date,
	test_run_qty = @test_run_qty,
	nguyenbo = @nguyenbo,
	mact = @mact,
	tenct = @tenct,
	nguyenlieu = @nguyenlieu,
	quycach = @quycach
WHERE id = @id


DECLARE @CNT INT
SET @CNT = 0

SELECT @CNT = COUNT(order_number) 
FROM tr_order_example_detail
WHERE Finished = 0
	AND f_cancelled = 'N'
	AND order_number = @order_number

IF @CNT = 0
BEGIN
	UPDATE tr_order_example
	SET Finished = 1
	WHERE order_number = @order_number
END","parseAnalysis":{"readsTables":["dbo.tr_material","dbo.tr_order_example_detail"],"writesTables":["dbo.tr_order_example","dbo.tr_order_example_detail"],"flags":["writes-multi-table"],"suggestedTier":"D"},"tablesEnriched":{"dbo.dqt_pallet_chitiet":"dqt_pallet_chitiet","dbo.dqt_thongke_phoi":"dqt_thongke_phoi","dbo.mes_hoso_donhang":"mes_hoso_donhang","dbo.ps_kehoach_donhang":"ps_kehoach_donhang","dbo.ps_kehoach_donhang_trangthai":"ps_kehoach_donhang_trangthai","dbo.tr_bophan":"tr_bophan","dbo.tr_chitiet_hangtrang":"tr_chitiet_hangtrang","dbo.tr_common":"tr_common","dbo.tr_dinhmuc_donggoi":"tr_dinhmuc_donggoi","dbo.tr_dinhmuc_govan":"tr_dinhmuc_govan","dbo.tr_dinhmuc_hangtrang":"tr_dinhmuc_hangtrang","dbo.tr_dinhmuc_ngukim":"tr_dinhmuc_ngukim","dbo.tr_dinhmuc_son":"tr_dinhmuc_son","dbo.tr_dinhmuc_son_new":"tr_dinhmuc_son_new","dbo.tr_dinhmuc_son_theomau":"tr_dinhmuc_son_theomau","dbo.tr_dondathang":"tr_dondathang","dbo.tr_dondathang_chitiet":"tr_dondathang_chitiet","dbo.tr_gridview_column":"tr_gridview_column","dbo.tr_luutrinh_sanxuat":"tr_luutrinh_sanxuat","dbo.tr_material":"tr_material","dbo.tr_nguyenlieu_gva":"tr_nguyenlieu_gva","dbo.tr_order":"tr_order","dbo.tr_order_detail":"tr_order_detail","dbo.tr_sanpham":"tr_sanpham","dbo.tr_tinhtrang_fsc":"tr_tinhtrang_fsc"}}
